const input = $input.first().json;
const action = input.action || 'get_time';

// Common timezone aliases
const aliases = {
  'est': 'America/New_York', 'eastern': 'America/New_York',
  'cst': 'America/Chicago', 'central': 'America/Chicago',
  'mst': 'America/Denver', 'mountain': 'America/Denver',
  'pst': 'America/Los_Angeles', 'pacific': 'America/Los_Angeles',
  'gmt': 'Europe/London', 'utc': 'Etc/UTC',
  'cet': 'Europe/Berlin', 'met': 'Europe/Berlin',
  'eet': 'Europe/Helsinki',
  'jst': 'Asia/Tokyo', 'ist': 'Asia/Kolkata',
  'cst_china': 'Asia/Shanghai', 'aest': 'Australia/Sydney',
  'nzst': 'Pacific/Auckland',
  'berlin': 'Europe/Berlin', 'london': 'Europe/London',
  'paris': 'Europe/Paris', 'tokyo': 'Asia/Tokyo',
  'new york': 'America/New_York', 'los angeles': 'America/Los_Angeles',
  'chicago': 'America/Chicago', 'denver': 'America/Denver',
  'sydney': 'Australia/Sydney', 'auckland': 'Pacific/Auckland',
  'mumbai': 'Asia/Kolkata', 'dubai': 'Asia/Dubai',
  'singapore': 'Asia/Singapore', 'hong kong': 'Asia/Hong_Kong',
  'shanghai': 'Asia/Shanghai', 'beijing': 'Asia/Shanghai',
  'moscow': 'Europe/Moscow', 'vienna': 'Europe/Vienna',
  'zurich': 'Europe/Zurich', 'amsterdam': 'Europe/Amsterdam',
  'rome': 'Europe/Rome', 'madrid': 'Europe/Madrid',
  'lisbon': 'Europe/Lisbon', 'stockholm': 'Europe/Stockholm',
  'warsaw': 'Europe/Warsaw', 'prague': 'Europe/Prague',
  'budapest': 'Europe/Budapest', 'athens': 'Europe/Athens',
  'istanbul': 'Europe/Istanbul', 'cairo': 'Africa/Cairo',
  'johannesburg': 'Africa/Johannesburg', 'nairobi': 'Africa/Nairobi',
  'sao paulo': 'America/Sao_Paulo', 'buenos aires': 'America/Argentina/Buenos_Aires',
  'mexico city': 'America/Mexico_City', 'toronto': 'America/Toronto',
  'vancouver': 'America/Vancouver', 'honolulu': 'Pacific/Honolulu',
  'anchorage': 'America/Anchorage', 'seoul': 'Asia/Seoul',
  'bangkok': 'Asia/Bangkok', 'jakarta': 'Asia/Jakarta'
};

function resolveTimezone(tz) {
  if (!tz) return 'Europe/Berlin';
  const lower = tz.toLowerCase().trim();
  return aliases[lower] || tz;
}

if (action === 'get_time') {
  const timezone = resolveTimezone(input.timezone);

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://timeapi.io/api/time/current/zone?timeZone=' + encodeURIComponent(timezone)
    });

    if (!data || !data.dateTime) {
      return [{ json: { error: 'Could not get time for timezone "' + timezone + '". Use IANA format (e.g. Europe/Berlin, America/New_York).' } }];
    }

    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const dayName = days[data.dayOfWeek] || data.dayOfWeek;

    let result = timezone + '\n';
    result += '  Date: ' + dayName + ', ' + data.date + '\n';
    result += '  Time: ' + data.time + '\n';
    result += '  UTC Offset: ' + (data.utcOffset || 'N/A') + '\n';
    result += '  DST: ' + (data.dstActive ? 'Yes' : 'No');

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get time: ' + err.message + '. Make sure timezone is valid IANA format (e.g. Europe/Berlin).' } }];
  }

} else if (action === 'convert_timezone') {
  const fromTz = resolveTimezone(input.from_timezone);
  const toTz = resolveTimezone(input.to_timezone);
  const datetime = input.datetime || '';

  if (!datetime) {
    return [{ json: { error: 'Parameter "datetime" is required (format: YYYY-MM-DD HH:MM:SS).' } }];
  }

  try {
    const body = {
      fromTimeZone: fromTz,
      dateTime: datetime,
      toTimeZone: toTz,
      dstAmbiguity: ''
    };

    const data = await helpers.httpRequest({
      method: 'POST',
      url: 'https://timeapi.io/api/conversion/converttimezone',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });

    if (!data || !data.conversionResult) {
      return [{ json: { error: 'Conversion failed. Check timezone names and datetime format (YYYY-MM-DD HH:MM:SS).' } }];
    }

    const cr = data.conversionResult;
    let result = 'Conversion Result\n';
    result += '  From: ' + fromTz + ' — ' + data.originalDateTime + '\n';
    result += '  To:   ' + toTz + ' — ' + cr.dateTime + '\n';
    result += '  UTC Offset: ' + (cr.utcOffset || 'N/A') + '\n';
    result += '  DST: ' + (cr.dstActive ? 'Yes' : 'No');

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Conversion failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use get_time or convert_timezone.' } }];
}
